uint8_t transcode_column(uint16_t column, enum transcode_mode mode)
{
    if (mode == TC_BINARY) {
        /*
         * Binary mode: pass raw data through.
         * Returns the low 8 bits of the 13-bit column value.
         */
        return (uint8_t)(column & 0xFFu);
    }

    if (mode == TC_HEX) {
        /*
         * Loader hex-nibble encoding: a hex digit (0..F) is punched as a set
         * of rows whose bit positions (rows 0..9) SUM to the nibble value
         * (e.g. row6+row8 -> 14 = 0xE; row2+row8 -> 10 = 0xA). Zone rows 10..12
         * are ignored. The loader nibble-packs two such columns into one byte.
         * Verified against the [1].pdf loader listing (38/40 bytes; the 2
         * differences are OCR noise in the trailing descriptor).
         */
        unsigned n = 0;
        for (int b = 0; b <= 9; b++)
            if (column & (1u << b))
                n += (unsigned)b;
        return (uint8_t)(n & 0x0Fu);
    }

    if (mode == TC_COLBIN) {
        /*
         * By-pass / column-binary read: one card column -> one 8-bit byte,
         * NOT nibble-packed. Each byte bit comes from a specific Hollerith
         * row: byte bit i <- card row B2R[i], B2R = {9,8,7,6,3,2,1,0}.
         * Low nibble (bits 0..3) from rows 9,8,7,6; high nibble (bits 4..7)
         * from rows 3,2,1,0; rows 4,5,11,12 unused. Card row 0 is the MSB.
         * Solved 2026-05-28 from the Burroughs reader firmware + .cap hole-art:
         * decodes the funktionalcpu program cards into valid GE code that
         * loads contiguously to 0x0100 with an entry JU at address 0.
         */
        static const int b2r[8] = {9, 8, 7, 6, 3, 2, 1, 0};
        uint8_t out = 0;
        for (int i = 0; i < 8; i++)
            if (column & (1u << b2r[i]))
                out |= (uint8_t)(1u << i);
        return out;
    }

    /*
     * TC_NORMAL: look up the 13-bit column value in the empirically derived
     * table.  Unobserved values default to 0x20 (GE space / blank column).
     */
    return hollerith_to_ge[column & 0x1FFFu];
}

